+#!/usr/bin/env npx tsx
+/**
+ * Build a C extension package as a .wasm side module for PyMode.
+ *
+ * Side modules are loaded at runtime by PythonDO via the dl_open/dl_sym
+ * host imports. They share linear memory with the main python.wasm and
+ * export PyInit_<name> functions that CPython calls through the standard
+ * _PyImport_FindSharedFuncptr() flow in dynload_pymode.c.
+ *
+ * Usage:
+ *     npx tsx scripts/build-extension.ts markupsafe
+ *     npx tsx scripts/build-extension.ts simplejson==3.19.3
+ *     npx tsx scripts/build-extension.ts --list    # show supported packages
+ *     npx tsx scripts/build-extension.ts --all     # build all supported
+ *
+ * Output:
+ *     .pymode/extensions/{name}/{module}.wasm  -- side module
+ *     .pymode/extensions/{name}/*.py           -- pure Python files from package
+ */
+
+import * as fs from "node:fs";
+import * as path from "node:path";
+import { execFileSync } from "node:child_process";
+import { mkdtempSync } from "node:fs";
+import { tmpdir } from "node:os";
+import { fileURLToPath } from "node:url";
+
+const SCRIPT_DIR = path.dirname(fileURLToPath(import.meta.url));
+const ROOT_DIR = path.dirname(SCRIPT_DIR);
+const EXT_DIR = path.join(ROOT_DIR, ".pymode", "extensions");
+const CPYTHON_DIR = path.join(ROOT_DIR, "cpython");
+const BUILD_DIR = path.join(ROOT_DIR, "build", "zig-wasi");
+
+const GREEN = "\x1b[0;32m";
+const YELLOW = "\x1b[1;33m";
+const RED = "\x1b[0;31m";
+const NC = "\x1b[0m";
+
+function info(msg: string): void {
+  console.log(`${GREEN}[INFO]${NC} ${msg}`);
+}
+
+function warn(msg: string): void {
+  console.log(`${YELLOW}[WARN]${NC} ${msg}`);
+}
+
+function error(msg: string): never {
+  console.error(`${RED}[ERROR]${NC} ${msg}`);
+  process.exit(1);
+}
+
+const CFLAGS_COMMON = [
+  "-target",
+  "wasm32-wasi",
+  "-Os",
+  "-DNDEBUG",
+  `-I${CPYTHON_DIR}/Include`,
+  `-I${CPYTHON_DIR}/Include/internal`,
+  `-I${BUILD_DIR}`,
+  "-Wno-error=int-conversion",
+  "-Wno-error=incompatible-pointer-types",
+];
+
+function runCapture(
+  cmd: string,
+  args: string[],
+): { returncode: number; stdout: string; stderr: string } {
+  try {
+    const stdout = execFileSync(cmd, args, {
+      stdio: ["pipe", "pipe", "pipe"],
+      encoding: "utf-8",
+    });
+    return { returncode: 0, stdout: stdout ?? "", stderr: "" };
+  } catch (e: any) {
+    return {
+      returncode: e.status ?? 1,
+      stdout: e.stdout ?? "",
+      stderr: e.stderr ?? "",
+    };
+  }
+}
+
+function compileSideModule(outputWasm: string, srcFiles: string[]): boolean {
+  const objDir = mkdtempSync(path.join(tmpdir(), "pymode-ext-"));
+  try {
+    const objects: string[] = [];
+    for (const src of srcFiles) {
+      const objName = path.basename(src).replace(".c", ".o");
+      const objPath = path.join(objDir, objName);
+      info(`  Compiling ${path.basename(src)}`);
+      const result = runCapture("zig", ["cc", ...CFLAGS_COMMON, "-c", src, "-o", objPath]);
+      if (result.returncode !== 0) {
+        warn(`  Failed to compile ${path.basename(src)}`);
+        return false;
+      }
+      objects.push(objPath);
+    }
+
+    if (objects.length === 0) {
+      warn("No object files produced");
+      return false;
+    }
+
+    info(`  Linking -> ${path.basename(outputWasm)}`);
+    const result = runCapture("zig", [
+      "cc",
+      "-target",
+      "wasm32-wasi",
+      "-nostdlib",
+      "-Os",
+      "-s",
+      "-Wl,--import-memory",
+      "-Wl,--allow-undefined",
+      "-Wl,--no-entry",
+      "-Wl,--export-dynamic",
+      ...objects,
+      "-o",
+      outputWasm,
+    ]);
+    if (result.returncode !== 0) {
+      if (result.stderr) {
+        error(`  Link error: ${result.stderr}`);
+      }
+      return false;
+    }
+    return true;
+  } finally {
+    fs.rmSync(objDir, { recursive: true, force: true });
+  }
+}
+
+function downloadSource(name: string, dest: string): void {
+  const dlDir = path.join(dest, "dl");
+  fs.mkdirSync(dlDir, { recursive: true });
+
+  // Try sdist first (has C source), fall back to wheel
+  let result = runCapture("pip3", ["download", "--no-binary", ":all:", name, "-d", dlDir]);
+  if (result.returncode !== 0) {
+    result = runCapture("pip3", ["download", name, "-d", dlDir]);
+    if (result.returncode !== 0) {
+      error(`Failed to download ${name}`);
+    }
+  }
+
+  const files = fs.readdirSync(dlDir);
+  const sdists = files.filter((f) => f.endsWith(".tar.gz"));
+  const wheels = files.filter((f) => f.endsWith(".whl"));
+
+  if (sdists.length > 0) {
+    execFileSync("tar", ["xzf", path.join(dlDir, sdists[0]), "-C", dest, "--strip-components=1"]);
+  } else if (wheels.length > 0) {
+    execFileSync("python3", ["-m", "zipfile", "-e", path.join(dlDir, wheels[0]), path.join(dest, "src")]);
+  } else {
+    error(`No sdist or wheel found for ${name}`);
+  }
+}
+
+function copyPyFiles(srcDir: string, destDir: string): void {
+  if (!fs.existsSync(srcDir)) return;
+  for (const entry of fs.readdirSync(srcDir, { withFileTypes: true })) {
+    if (entry.isFile() && entry.name.endsWith(".py")) {
+      fs.copyFileSync(path.join(srcDir, entry.name), path.join(destDir, entry.name));
+    }
+  }
+}
+
+interface ExtensionDef {
+  info_msg: string;
+  src_dirs: string[];
+  c_file: string;
+  wasm: string;
+}
+
+const EXTENSIONS: Record<string, ExtensionDef> = {
+  markupsafe: {
+    info_msg: "Building markupsafe (_speedups.wasm)...",
+    src_dirs: ["src/markupsafe", "markupsafe"],
+    c_file: "_speedups.c",
+    wasm: "_speedups.wasm",
+  },
+  simplejson: {
+    info_msg: "Building simplejson (_speedups.wasm)...",
+    src_dirs: ["simplejson"],
+    c_file: "_speedups.c",
+    wasm: "_speedups.wasm",
+  },
+  msgpack: {
+    info_msg: "Building msgpack (_cmsgpack.wasm)...",
+    src_dirs: ["msgpack"],
+    c_file: "_cmsgpack.c",
+    wasm: "_cmsgpack.wasm",
+  },
+  pyyaml: {
+    info_msg: "Building pyyaml (_yaml.wasm)...",
+    src_dirs: ["yaml", "."],
+    c_file: "_yaml.c",
+    wasm: "_yaml.wasm",
+  },
+};
+
+function buildExt(name: string): void {
+  const pkgDir = path.join(EXT_DIR, name);
+  fs.mkdirSync(pkgDir, { recursive: true });
+
+  const lookup = name.toLowerCase();
+  if (!(lookup in EXTENSIONS)) {
+    error(`Unknown extension: ${name}. Run with --list to see supported packages.`);
+  }
+
+  const ext = EXTENSIONS[lookup];
+  info(ext.info_msg);
+  downloadSource(name, pkgDir);
+
+  // Find source directory
+  let srcDir: string | null = null;
+  for (const candidate of ext.src_dirs) {
+    const p = path.join(pkgDir, candidate);
+    if (fs.existsSync(path.join(p, ext.c_file))) {
+      srcDir = p;
+      break;
+    }
+  }
+
+  if (!srcDir) {
+    error(`${ext.c_file} not found`);
+  }
+
+  const cPath = path.join(srcDir, ext.c_file);
+  const wasmPath = path.join(pkgDir, ext.wasm);
+
+  if (!compileSideModule(wasmPath, [cPath])) {
+    error(`Failed to compile ${name}`);
+  }
+
+  copyPyFiles(srcDir, pkgDir);
+
+  // Report
+  for (const f of fs.readdirSync(pkgDir)) {
+    if (f.endsWith(".wasm")) {
+      const size = fs.statSync(path.join(pkgDir, f)).size;
+      info(`Built: ${path.join(pkgDir, f)} (${Math.floor(size / 1024)}KB)`);
+    }
+  }
+}
+
+function listExtensions(): void {
+  console.log("Supported C extension packages:");
+  console.log("  markupsafe   - HTML escaping (1 C file, ~15KB .wasm)");
+  console.log("  simplejson   - Fast JSON encoder/decoder (1 C file)");
+  console.log("  msgpack      - MessagePack serialization (1 C file)");
+  console.log("  pyyaml       - YAML parser (requires libyaml headers)");
+  console.log();
+  console.log("Usage:");
+  console.log("  npx tsx scripts/build-extension.ts markupsafe");
+  console.log("  npx tsx scripts/build-extension.ts --all");
+  console.log();
+  console.log("Output goes to .pymode/extensions/<name>/<module>.wasm");
+  console.log("These .wasm files are loaded at runtime by PythonDO via dl_open/dl_sym.");
+}
+
+function buildAll(): void {
+  let failed = 0;
+  for (const ext of ["markupsafe", "simplejson", "msgpack"]) {
+    try {
+      buildExt(ext);
+    } catch {
+      warn(`Failed to build ${ext}`);
+      failed++;
+    }
+  }
+
+  if (failed === 0) {
+    info("All extensions built successfully");
+  } else {
+    warn(`${failed} extension(s) failed to build`);
+  }
+}
+
+function main(): void {
+  // Check prerequisites
+  try {
+    execFileSync("zig", ["version"], { stdio: "pipe" });
+  } catch {
+    error("zig not found. Install: https://ziglang.org/download/");
+  }
+  if (!fs.existsSync(path.join(CPYTHON_DIR, "Include"))) {
+    error("CPython not found. Run build-phase1.sh first.");
+  }
+  if (!fs.existsSync(path.join(BUILD_DIR, "pyconfig.h"))) {
+    error("pyconfig.h not found. Run build-phase2.ts first.");
+  }
+
+  const args = process.argv.slice(2);
+  if (args.length < 1) {
+    error("Usage: build-extension.ts <package-name> | --list | --all");
+  }
+
+  const arg = args[0];
+  if (arg === "--list" || arg === "-l") {
+    listExtensions();
+  } else if (arg === "--all" || arg === "-a") {
+    buildAll();
+  } else {
+    buildExt(arg);
+  }
+}
+
+main();

@@ -0,0 +1,707 @@
+#!/usr/bin/env npx tsx
+/**
+ * Phase 2: Build CPython for wasm32-wasi using zig cc (no WASI SDK).
+ *
+ * Uses ReleaseSmall equivalent: -Os, strip debug info, minimize binary size.
+ * Prerequisites: python3, wasmtime, zig, Phase 1 native build.
+ */
+
+import { execSync, spawnSync } from "node:child_process";
+import {
+  accessSync,
+  chmodSync,
+  constants,
+  copyFileSync,
+  existsSync,
+  lstatSync,
+  mkdirSync,
+  readFileSync,
+  readdirSync,
+  renameSync,
+  rmSync,
+  statSync,
+  unlinkSync,
+  writeFileSync,
+} from "node:fs";
+import { cpus, platform, arch } from "node:os";
+import { basename, dirname, extname, join, resolve } from "node:path";
+import { fileURLToPath } from "node:url";
+
+const SCRIPT_DIR = dirname(fileURLToPath(import.meta.url));
+const ROOT_DIR = dirname(SCRIPT_DIR);
+const CPYTHON_DIR = join(ROOT_DIR, "cpython");
+const BUILD_DIR = join(ROOT_DIR, "build", "zig-wasi");
+const ZIG_WRAPPER_DIR = join(ROOT_DIR, "build", "zig-wrappers");
+
+const GREEN = "\x1b[0;32m";
+const YELLOW = "\x1b[1;33m";
+const RED = "\x1b[0;31m";
+const NC = "\x1b[0m";
+
+function info(msg: string): void {
+  console.log(`${GREEN}[INFO]${NC} ${msg}`);
+}
+
+function warn(msg: string): void {
+  console.log(`${YELLOW}[WARN]${NC} ${msg}`);
+}
+
+function error(msg: string): never {
+  console.error(`${RED}[ERROR]${NC} ${msg}`);
+  process.exit(1);
+}
+
+function ncpu(): number {
+  return cpus().length || 2;
+}
+
+function sedi(filepath: string, pattern: RegExp, replacement: string): void {
+  let content = readFileSync(filepath, "utf-8");
+  content = content.replace(pattern, replacement);
+  writeFileSync(filepath, content);
+}
+
+function which(cmd: string): string | null {
+  try {
+    const result = execSync(`command -v ${cmd}`, {
+      encoding: "utf-8",
+      stdio: ["pipe", "pipe", "pipe"],
+    }).trim();
+    return result || null;
+  } catch {
+    return null;
+  }
+}
+
+function isExecutable(filepath: string): boolean {
+  try {
+    accessSync(filepath, constants.X_OK);
+    return true;
+  } catch {
+    return false;
+  }
+}
+
+interface NativeModule {
+  name: string;
+  zig_src?: string;
+  c_srcs?: string[];
+  c_flags?: string[];
+  extra_includes?: string[];
+}
+
+function main(): void {
+  // Check prerequisites
+  for (const cmd of ["python3", "wasmtime", "zig"]) {
+    if (!which(cmd)) {
+      error(`${cmd} not found`);
+    }
+  }
+
+  const zigVersion = execSync("zig version", { encoding: "utf-8" }).trim();
+  info(`Using zig ${zigVersion}`);
+
+  if (!existsSync(CPYTHON_DIR) || !statSync(CPYTHON_DIR).isDirectory()) {
+    error("CPython source not found. Run build-phase1.sh first to clone it.");
+  }
+
+  // Step 1: Locate or build the native Python (needed for cross-compilation)
+  let nativePython = "";
+  const candidates = [
+    join(CPYTHON_DIR, "cross-build", "build", "python.exe"),
+    join(CPYTHON_DIR, "cross-build", "build", "python"),
+    join(ROOT_DIR, "build", "native", "python.exe"),
+    join(ROOT_DIR, "build", "native", "python"),
+  ];
+  for (const candidate of candidates) {
+    if (existsSync(candidate) && statSync(candidate).isFile() && isExecutable(candidate)) {
+      nativePython = candidate;
+      break;
+    }
+  }
+
+  if (!nativePython) {
+    info("No native Python found. Building one (out-of-tree)...");
+    const nativeBuildDir = join(ROOT_DIR, "build", "native");
+    mkdirSync(nativeBuildDir, { recursive: true });
+    const configureResult = spawnSync(
+      join(CPYTHON_DIR, "configure"),
+      [`--prefix=${nativeBuildDir}/install`],
+      { cwd: nativeBuildDir, stdio: "inherit" },
+    );
+    if (configureResult.status !== 0) {
+      error("Native Python configure failed");
+    }
+    const makeResult = spawnSync("make", [`-j${ncpu()}`], {
+      cwd: nativeBuildDir,
+      stdio: "inherit",
+    });
+    if (makeResult.status !== 0) {
+      error("Native Python make failed");
+    }
+    for (const name of ["python.exe", "python"]) {
+      const path = join(nativeBuildDir, name);
+      if (existsSync(path) && statSync(path).isFile() && isExecutable(path)) {
+        nativePython = path;
+        break;
+      }
+    }
+  }
+
+  info(`Using native Python: ${nativePython}`);
+
+  // Step 2: Create zig cc wrapper scripts
+  mkdirSync(ZIG_WRAPPER_DIR, { recursive: true });
+
+  const zigCcScript = join(ZIG_WRAPPER_DIR, "zig-cc");
+  writeFileSync(
+    zigCcScript,
+    `#!/usr/bin/env bash
+# zig cc wrapper for wasm32-wasi cross-compilation
+# Applies ReleaseSmall: -Os, strip, no debug info
+
+ARGS=()
+HAS_OPT=0
+for arg in "$@"; do
+    case "$arg" in
+        # Skip flags zig cc doesn't support for wasm32-wasi
+        -pthread|-ldl|-lutil|-lrt|-lpthread) continue ;;
+        # Keep -lm (zig provides this for wasm32-wasi)
+        -lm) ARGS+=("$arg") ;;
+        -Wl,--version-script=*) continue ;;
+        -Wl,-export-dynamic|-Wl,--no-as-needed) continue ;;
+        -Wl,--allow-undefined) continue ;;
+        -Wl,-z,*) continue ;;
+        -Wl,--initial-memory=*) continue ;;
+        -Wl,--stack-first) continue ;;
+        -z) continue ;;  # next arg is the z-flag value
+        stack-size=*) continue ;;
+        # Replace optimization flags with -Os (ReleaseSmall)
+        -O0|-O1|-O2|-O3|-Og) ARGS+=("-Os"); HAS_OPT=1 ;;
+        -flto=thin) ARGS+=("-flto") ;;
+        # Skip macOS-specific flags
+        -framework) continue ;;
+        CoreFoundation|SystemConfiguration) continue ;;
+        -Wl,-stack_size,*) continue ;;
+        # Skip dynamic linking flags (WASI is static)
+        -bundle|-undefined|-dynamic_lookup) continue ;;
+        -Wl,-undefined,*) continue ;;
+        # Skip native host library paths (not valid for cross-compilation)
+        -L/opt/homebrew/*|-L/usr/local/*) continue ;;
+        -lb2) continue ;;  # libb2 not available as WASM
+        # Pass everything else through
+        *) ARGS+=("$arg") ;;
+    esac
+done
+
+# Ensure -Os is always set for ReleaseSmall
+if [ "$HAS_OPT" -eq 0 ]; then
+    ARGS+=("-Os")
+fi
+
+# Strip debug info for smaller binary
+ARGS+=("-s")
+
+# WASI defines CLOCK_REALTIME/CLOCK_MONOTONIC as pointers, not integers.
+# Zig's clang treats -Wint-conversion as an error by default, so demote it.
+ARGS+=("-Wno-error=int-conversion" "-Wno-error=incompatible-pointer-types" "-Wno-error=date-time")
+
+exec zig cc -target wasm32-wasi "\${ARGS[@]}"
+`,
+  );
+  chmodSync(zigCcScript, 0o755);
+
+  const wrappers: Array<[string, string]> = [
+    ["zig-ar", "#!/usr/bin/env bash\nexec zig ar \"$@\"\n"],
+    ["zig-ranlib", "#!/usr/bin/env bash\nexec zig ranlib \"$@\"\n"],
+  ];
+  for (const [name, content] of wrappers) {
+    const path = join(ZIG_WRAPPER_DIR, name);
+    writeFileSync(path, content);
+    chmodSync(path, 0o755);
+  }
+
+  const zigCppScript = join(ZIG_WRAPPER_DIR, "zig-cpp");
+  writeFileSync(
+    zigCppScript,
+    `#!/usr/bin/env bash
+ARGS=()
+for arg in "$@"; do
+    case "$arg" in
+        -pthread|-lpthread|-ldl|-lm|-lutil|-lrt) continue ;;
+        -framework|CoreFoundation|SystemConfiguration) continue ;;
+        *) ARGS+=("$arg") ;;
+    esac
+done
+exec zig cc -target wasm32-wasi -E "\${ARGS[@]}"
+`,
+  );
+  chmodSync(zigCppScript, 0o755);
+
+  // Step 3: Out-of-tree build with zig cc
+  info("Configuring CPython with zig cc for wasm32-wasi (ReleaseSmall)...");
+  mkdirSync(BUILD_DIR, { recursive: true });
+
+  // Clean previous zig-wasi build
+  for (const item of readdirSync(BUILD_DIR)) {
+    const path = join(BUILD_DIR, item);
+    const st = lstatSync(path);
+    if (st.isDirectory()) {
+      rmSync(path, { recursive: true, force: true });
+    } else {
+      unlinkSync(path);
+    }
+  }
+
+  const configCache = join(dirname(BUILD_DIR), "config.cache");
+  if (existsSync(configCache)) {
+    unlinkSync(configCache);
+  }
+
+  // Detect build triple
+  const system = platform();
+  const machine = arch();
+  // Map Node.js arch names to platform convention
+  const machineMap: Record<string, string> = {
+    arm64: "aarch64",
+    x64: "x86_64",
+    ia32: "i686",
+  };
+  const mappedMachine = machineMap[machine] || machine;
+
+  let buildTriple: string;
+  if (system === "darwin") {
+    buildTriple = `${mappedMachine}-apple-darwin`;
+  } else if (system === "linux") {
+    buildTriple = `${mappedMachine}-pc-linux-gnu`;
+  } else {
+    buildTriple = `${mappedMachine}-unknown-${system}`;
+  }
+
+  // Disabled modules
+  const disabledModules = [
+    "py_cv_module__bz2=n/a",
+    "py_cv_module__lzma=n/a",
+    "py_cv_module_zlib=n/a",
+    "py_cv_module__socket=n/a",
+    "py_cv_module__ctypes=n/a",
+    "py_cv_module_select=n/a",
+    "py_cv_module_faulthandler=n/a",
+    "py_cv_module_resource=n/a",
+    "py_cv_module_grp=n/a",
+    "py_cv_module_pwd=n/a",
+    "py_cv_module_fcntl=n/a",
+    "py_cv_module_mmap=n/a",
+    "py_cv_module_termios=n/a",
+    "py_cv_module_syslog=n/a",
+    "py_cv_module__multiprocessing=n/a",
+    "py_cv_module__posixsubprocess=n/a",
+    "py_cv_module__posixshmem=n/a",
+    "py_cv_module__curses=n/a",
+    "py_cv_module__curses_panel=n/a",
+    "py_cv_module__dbm=n/a",
+    "py_cv_module__gdbm=n/a",
+    "py_cv_module__tkinter=n/a",
+    "py_cv_module__scproxy=n/a",
+  ];
+
+  const configureEnv: Record<string, string> = {
+    ...process.env as Record<string, string>,
+    CONFIG_SITE: join(ROOT_DIR, "scripts", "config.site-wasi"),
+    PKG_CONFIG: "false",
+  };
+
+  const configureResult = spawnSync(
+    join(CPYTHON_DIR, "configure"),
+    [
+      "--host=wasm32-wasi",
+      `--build=${buildTriple}`,
+      `--with-build-python=${nativePython}`,
+      `CC=${zigCcScript}`,
+      `CPP=${zigCppScript}`,
+      `AR=${join(ZIG_WRAPPER_DIR, "zig-ar")}`,
+      `RANLIB=${join(ZIG_WRAPPER_DIR, "zig-ranlib")}`,
+      "CFLAGS=-Os -DNDEBUG -fno-strict-aliasing -msimd128",
+      "LDFLAGS=-s",
+      "--disable-ipv6",
+      "--disable-shared",
+      "--without-ensurepip",
+      "--without-pymalloc",
+      "--disable-test-modules",
+      "--config-cache",
+      "ac_cv_file__dev_ptmx=no",
+      "ac_cv_file__dev_ptc=no",
+      ...disabledModules,
+    ],
+    { cwd: BUILD_DIR, env: configureEnv, stdio: "inherit" },
+  );
+  if (configureResult.status !== 0) {
+    error("Configure failed");
+  }
+
+  // Step 3b: Patch pyconfig.h - use CPython pthread types instead of musl
+  info("Patching pyconfig.h for WASI...");
+  const pyconfig = join(BUILD_DIR, "pyconfig.h");
+  sedi(pyconfig, /^#define HAVE_PTHREAD_H 1/m, "/* #undef HAVE_PTHREAD_H */");
+
+  // Step 3b2: Save clean config.c as base (before variant patching)
+  const configC = join(BUILD_DIR, "Modules", "config.c");
+  const configCBase = join(BUILD_DIR, "Modules", "config.c.base");
